540 void Instruction::dropUBImplyingAttrsAndUnknownMetadata(
541     ArrayRef<unsigned> KnownIDs) {
542   dropUnknownNonDebugMetadata(KnownIDs);
543   auto *CB = dyn_cast<CallBase>(this);
544   if (!CB)
545     return;
546   // For call instructions, we also need to drop parameter and return attributes
547   // that can cause UB if the call is moved to a location where the attribute is
548   // not valid.
549   AttributeList AL = CB->getAttributes();
550   if (AL.isEmpty())
551     return;
552   AttributeMask UBImplyingAttributes =
553       AttributeFuncs::getUBImplyingAttributes();
554   for (unsigned ArgNo = 0; ArgNo < CB->arg_size(); ArgNo++)
555     CB->removeParamAttrs(ArgNo, UBImplyingAttributes);
556   CB->removeRetAttrs(UBImplyingAttributes);
557 }
