559 void Instruction::dropUBImplyingAttrsAndMetadata(ArrayRef<unsigned> Keep) {
560   // !annotation and !prof metadata does not impact semantics.
561   // !range, !nonnull and !align produce poison, so they are safe to speculate.
562   // !noundef and various AA metadata must be dropped, as it generally produces
563   // immediate undefined behavior.
564   static const unsigned KnownIDs[] = {
565       LLVMContext::MD_annotation, LLVMContext::MD_range,
566       LLVMContext::MD_nonnull, LLVMContext::MD_align, LLVMContext::MD_prof};
567   SmallVector<unsigned> KeepIDs;
568   KeepIDs.reserve(Keep.size() + std::size(KnownIDs));
569   append_range(KeepIDs, (!ProfcheckDisableMetadataFixes ? KnownIDs
570                                                         : drop_end(KnownIDs)));
571   append_range(KeepIDs, Keep);
572   dropUBImplyingAttrsAndUnknownMetadata(KeepIDs);
573 }
