575 bool Instruction::hasUBImplyingAttrs() const {
576   auto *CB = dyn_cast<CallBase>(this);
577   if (!CB)
578     return false;
579   // For call instructions, we also need to check parameter and return
580   // attributes that can cause UB.
581   for (unsigned ArgNo = 0; ArgNo < CB->arg_size(); ArgNo++)
582     if (CB->isPassingUndefUB(ArgNo))
583       return true;
584   return CB->hasRetAttr(Attribute::NoUndef) ||
585          CB->hasRetAttr(Attribute::Dereferenceable) ||
586          CB->hasRetAttr(Attribute::DereferenceableOrNull);
